// ── Daily Challenge Question Bank ────────────────────────────────────────────
// Scenario-based questions, separate from the topic question banks.
// The daily seeded shuffle picks 10 from this pool each day.

export const DAILY_QUESTIONS = {
  he: [
    // ── Workloads ──
    {q:"Pod בשם api-server מציג סטטוס CrashLoopBackOff. מה הצעד הראשון לאבחון?",options:["kubectl delete pod api-server","kubectl logs api-server --previous","kubectl edit pod api-server","kubectl drain node"],answer:1,explanation:"--previous מציג לוגים מהריצה שקרסה. זה תמיד הצעד הראשון כשיש CrashLoopBackOff – הלוגים יחשפו את שגיאת האתחול."},
    {q:"Pod נשאר Pending. kubectl describe מציג: '0/3 nodes available: 3 Insufficient memory'. מה הפתרון הנכון?",options:["הפעלת Pod מחדש","שינוי namespace","הורדת memory requests של ה-Pod או הוספת Node","מחיקת Pods אחרים"],answer:2,explanation:"ה-Scheduler לא מוצא Node עם זיכרון פנוי שיכסה את ה-requests. יש להוריד את דרישות הזיכרון של ה-Pod או להוסיף Node לאשכול."},
    {q:"Rolling update של Deployment נתקע – Pod חדש נוצר אבל לא עולה לReady. מה הסיבה הנפוצה ביותר?",options:["image לא קיים בrepo","readiness probe נכשלת על ה-Pod החדש","אין DNS","RBAC חסר"],answer:1,explanation:"כשrollout נתקע, הסיבה הנפוצה ביותר היא readiness probe כושלת – Kubernetes מחכה לPod להיות Ready לפני שממשיך לעדכן Pods נוספים."},
    {q:"Pod קרס עם OOMKilled. מה המשמעות ומה הצעד הבא?",options:["בעיית רשת – בודקים NetworkPolicy","הקרנל סיים את הקונטיינר כי חרג מmemory limit – מגדילים limits.memory","image פגום – מושכים מחדש","CPU throttling – מגדילים CPU"],answer:1,explanation:"OOMKilled = Out Of Memory Killed. הקרנל הרג את הקונטיינר מאחר חרג ממגבלת הזיכרון. יש להגדיל את limits.memory או לאתר memory leak באפליקציה."},
    {q:"HPA מוגדר ל-Deployment, אך לא מבצע scale למרות עומס CPU גבוה. מה הסיבה הסבירה ביותר?",options:["אין Ingress","metrics-server לא מותקן או לא עובד","maxReplicas נמוך מדי","namespace שגוי"],answer:1,explanation:"HPA תלוי ב-metrics-server כדי לקרוא נתוני CPU/memory. ללא metrics-server, ה-HPA לא יכול לקבל מדדים ולכן לא מבצע scaling."},
    {q:"Init Container נכשל בכל ניסיון עם exit code 1. הLogs מציגים 'connection refused'. מה בודקים?",options:["resource limits של ה-init container","האם השירות שה-init container מחכה לו בכלל פעיל","image tag שגוי","namespace שגוי"],answer:1,explanation:"Init containers משמשים לרוב להמתנה לשירות חיצוני. connection refused אומר שהיעד לא זמין. יש לוודא שה-dependency כבר רץ ופועל."},
    {q:"Deployment מנסה להריץ 5 replicas אך רק 3 עולים. kubectl describe מציג 'pod didn't trigger scale-up'. מה בודקים?",options:["cluster autoscaler לא מוגדר או Nodes לא יכולים להתרחב","image שגוי","secrets חסרים","namespace quota"],answer:0,explanation:"כש-Pods לא יכולים להיות scheduled, Cluster Autoscaler אמור להוסיף Nodes. אם זה לא קורה – ייתכן שאין תצורת autoscaling, הgit quota ממלאה, או שאין cloud instances זמינות."},
    {q:"Job רץ אך לעולם לא מסתיים. kubectl get job מציג COMPLETIONS 0/1 כבר שעה. מה בודקים?",options:["מחיקת ה-Job ויצירה מחדש","kubectl logs של Pod ה-Job – ייתכן שהתהליך תקוע","kubectl describe node","שינוי restartPolicy"],answer:1,explanation:"Job שלא מסתיים בד\"כ תקוע בתהליך שלא יוצא. יש לראות לוגים של ה-Pod כדי להבין אם זה deadlock, קלט חסר, או תהליך אינסופי."},
    {q:"Pod מציג READY 0/1 אך STATUS Running. הAפליקציה בפנים עובדת. מה הבעיה?",options:["liveness probe נכשלת","readiness probe נכשלת – הPod לא מקבל traffic","image שגוי","resource limits נמוכים"],answer:1,explanation:"0/1 Ready אומר שreadiness probe נכשלת. ה-Pod רץ אבל לא יקבל traffic מה-Service. יש לבדוק את הגדרת ה-readiness probe ולוודא שהPath/Port נכונים."},
    {q:"StatefulSet database-0 קרס ולא עולה מחדש. kubectl describe מציג 'volume is already exclusively attached'. מה קרה?",options:["image חסר","ה-PVC עם ReadWriteOnce מחובר ל-Node אחר – Node drain לא הושלם","namespace שגוי","RBAC חסר"],answer:1,explanation:"ReadWriteOnce מאפשר חיבור לNode אחד בלבד. אם ה-Node הקודם לא שחרר את ה-volume לחלוטין (למשל לאחר crash), ה-Pod החדש לא יכול לחבר אותו. פתרון: לחכות לNode detach או לאלץ detach."},

    // ── Networking ──
    {q:"kubectl get endpoints my-svc מציג '<none>'. Service קיים, Pods רצים. מה הבעיה?",options:["חסר Ingress","selector של Service לא תואם labels של Pods","חסר NodePort","חסר NetworkPolicy"],answer:1,explanation:"כשEndpoints ריק, זה כמעט תמיד חוסר התאמה בין selector של ה-Service לבין labels של ה-Pods. בודקים עם kubectl get pods --show-labels."},
    {q:"Pod לא מצליח לפנות לשירות אחר באשכול. curl http://my-svc.default.svc.cluster.local מחזיר 'Could not resolve host'. מה בודקים?",options:["NetworkPolicy","CoreDNS Pods בkube-system – האם הם רצים ובריאים","Ingress","service type"],answer:1,explanation:"שגיאת DNS בתוך האשכול מצביעה על CoreDNS. יש לבדוק: kubectl get pods -n kube-system | grep coredns ולוודא שהם Running ו-Ready."},
    {q:"Ingress מוגדר, DNS מצביע נכון, אך כל הבקשות מחזירות 404. מה בודקים?",options:["TLS cert","path ב-Ingress rule לא תואם ל-path שהאפליקציה מאזינה לו","namespace של Ingress","image של Pod"],answer:1,explanation:"404 מ-Ingress בד\"כ אומר שה-path rule לא תואם. אם האפליקציה מאזינה על / אבל ה-Ingress מגדיר path: /api, הנתיב לא יתאים. יש לבדוק path ו-pathType."},
    {q:"NetworkPolicy הוחלה על namespace. עכשיו Pod A לא יכול לדבר עם Pod B באותו namespace. מה קרה?",options:["NetworkPolicy ב-K8s default-deny – לא הוגדרה allow rule בין הPods","Pods בnamespaces שונים","Service לא קיים","DNS כשל"],answer:0,explanation:"NetworkPolicy ב-Kubernetes היא additive allow-list. כשמחילים policy, כל traffic שלא מוגדר במפורש כ-allow נחסם. יש להוסיף ingress rule שמאפשרת תקשורת בתוך ה-namespace."},
    {q:"Service מסוג LoadBalancer נשאר בסטטוס Pending (EXTERNAL-IP <pending>) בsingle-node local cluster. מה הסיבה?",options:["חסר Ingress","LoadBalancer דורש cloud provider עם integration – ב-local cluster אין זה","חסר DNS","חסר TLS"],answer:1,explanation:"ServiceType LoadBalancer מסתמך על cloud provider (AWS, GCP, Azure) שיקצה IP חיצוני. ב-local cluster (minikube, kind) זה לא זמין ללא כלים כמו MetalLB. לשימוש local משתמשים ב-NodePort."},
    {q:"Pod לא יכול לגשת לאינטרנט. curl google.com נכשל, אבל Pod אחר באותו namespace כן מצליח. מה בודקים?",options:["kubectl logs","NetworkPolicy על ה-Pod הספציפי שחוסמת egress","image שגוי","DNS"],answer:1,explanation:"אם Pod אחד לא יכול לגשת לחוץ אבל אחרים כן, NetworkPolicy egress היא החשודה הראשית. יש לבדוק policies שחלות על ה-Pod לפי labels."},
    {q:"Service ClusterIP נגיש מתוך הPods, אך NodePort על port 30080 לא נגיש מחוץ לאשכול. מה הסיבה האפשרית?",options:["firewall/security group חוסמים port 30080","חסר Ingress","DNS שגוי","RBAC"],answer:0,explanation:"NodePort פותח port על כל ה-Nodes, אך firewall חיצוני (security groups, iptables) עלול לחסום אותו. יש לוודא שport 30080 פתוח ב-security group ושאין iptables rule שחוסמת."},

    // ── Config & Security ──
    {q:"Pod לא מצליח לפנות ל-Secrets שיצרת. kubectl describe pod מציג 'secret not found'. מה בודקים?",options:["RBAC","האם ה-Secret נמצא באותו namespace כמו ה-Pod","הצפנה של ה-Secret","image pull"],answer:1,explanation:"Secrets ו-Pods חייבים להיות באותו namespace. Secret בnamespace A לא נגיש ל-Pod בnamespace B. יש לוודא שהSecret נוצר בnamespace הנכון."},
    {q:"ServiceAccount של Pod מנסה לבצע kubectl get pods ומקבל 'Forbidden'. Role קיים. מה חסר?",options:["הגדלת resource limits","RoleBinding שמחבר את ה-Role ל-ServiceAccount","ClusterRole","Secret"],answer:1,explanation:"Role לבד לא מספיקה. יש צורך ב-RoleBinding שמחבר בין ה-Role (הרשאות) לבין ה-Subject (ServiceAccount). ללא RoleBinding, ה-Role לא תקפה."},
    {q:"ConfigMap עודכן עם ערכים חדשים, אך האפליקציה ב-Pod עדיין רואה ערכים ישנים. למה?",options:["ConfigMap לא תקין","רוב האפליקציות טוענות ConfigMap פעם אחת בהפעלה – Pod צריך restart","RBAC חסם את ה-ConfigMap","namespace שגוי"],answer:1,explanation:"כשConfigMap מוגדר כ-env vars, השינויים יכנסו לתוקף רק אחרי restart של ה-Pod. אם מוגדר כvolume, עדכון יכול להגיע בתוך כמה דקות – אבל האפליקציה עצמה צריכה לקרוא מחדש."},
    {q:"Pod מנסה לפנות ל-private Docker registry ומקבל 'ImagePullBackOff'. מה חסר?",options:["resource limits","imagePullSecrets לא מוגדר ב-Pod spec – חסר Secret עם credentials ל-registry","NetworkPolicy","Node taints"],answer:1,explanation:"כדי למשוך image מ-private registry, ה-Pod צריך imagePullSecrets שמפנה ל-Secret מסוג kubernetes.io/dockerconfigjson עם credentials של ה-registry."},
    {q:"Pod מנסה לרוץ כ-root (uid 0) אבל נדחה. מה הסיבה הסבירה?",options:["חסר NetworkPolicy","PodSecurityAdmission או PodSecurityPolicy מגדיר runAsNonRoot: true","חסר PVC","חסר Service"],answer:1,explanation:"PodSecurity admission control יכול לאסור הרצה כroot. אם namespace מוגדר עם policy restricted או baseline, Pods שמנסים לרוץ כroot יידחו. יש לשנות securityContext.runAsUser."},
    {q:"Secret מוגדר ב-Pod כenv var: value = 'dXNlcjpwYXNz'. האפליקציה מקבלת את הסטרינג הזה, לא את 'user:pass'. מה הבעיה?",options:["Secret מסוג שגוי","Secret נשמר ב-base64 אך K8s מפענח אוטומטית – אם האפליקציה מקבלת base64, נוצר Secret עם ערך שכבר encoded פעמיים","RBAC","namespace שגוי"],answer:1,explanation:"K8s מפענח Secret מbase64 אוטומטית כשמזריק לPod. אם נוצר Secret עם ערך שכבר base64 encoded, ה-Pod יקבל base64 במקום הערך האמיתי. יש ליצור Secret עם הערך הגולמי."},

    // ── Storage ──
    {q:"PVC בסטטוס Pending. kubectl describe pvc מציג 'storageclass.storage.k8s.io not found'. מה הבעיה?",options:["חסר Namespace","StorageClass שצוין ב-PVC לא קיים באשכול – בדוק עם kubectl get storageclass","PV מלא","Secret חסר"],answer:1,explanation:"PVC מפנה ל-StorageClass שלא קיים. יש לוודא ששם ה-StorageClass ב-PVC תואם לאחד מה-StorageClasses הקיימים (kubectl get storageclass)."},
    {q:"שני Pods מנסים לחבר אותו PVC. ה-Pod השני נשאר Pending עם 'Multi-Attach error'. מה הסיבה?",options:["חסר NetworkPolicy","PVC עם accessMode ReadWriteOnce (RWO) יכול להיות מחובר לNode אחד בלבד","חסר Secret","Resource limits"],answer:1,explanation:"ReadWriteOnce אומר שהvolume יכול להיות mounted ל-Node אחד בלבד בכל זמן נתון. אם שני Pods על Nodes שונים מנסים לחבר, ה-Pod השני נחסם. פתרון: שינוי ל-ReadWriteMany אם ה-storage backend תומך."},
    {q:"Helm upgrade נכשל עם 'cannot patch because a resource with that name already exists (not managed by Helm)'. מה קרה?",options:["values.yaml שגוי","משאב נוצר ידנית מחוץ ל-Helm ולכן Helm לא מנהל אותו – משתמשים ב-helm upgrade --force או מוחקים ידנית","namespace שגוי","image שגוי"],answer:1,explanation:"Helm עוקב אחרי משאבים שהוא יצר. אם משאב נוצר ידנית עם אותו שם, Helm לא יכול לנהל אותו. אפשר להשתמש ב-kubectl annotate לסמן אותו כmanaged by Helm, או למחוק ולאפשר ל-Helm ליצור מחדש."},
    {q:"PV נמחק בזמן שPVC עדיין קיים. PVC עכשיו בסטטוס 'Lost'. מה עושים?",options:["מוחקים את ה-PVC ומחכים","יוצרים PV חדש עם claimRef שמצביע על ה-PVC הקיים","kubectl restart pvc","מחיקת namespace"],answer:1,explanation:"כש-PV נמחק, ה-PVC עובר לסטטוס Lost. יש ליצור PV חדש עם spec.claimRef שמצביע על הnamespace/שם של ה-PVC הקיים, כך ה-binding יוחזר."},
    {q:"Pod מנסה לכתוב לvolume אך מקבל 'Read-only file system'. PVC מוגדר ב-YAML. מה בודקים?",options:["accessMode ReadWriteOnce בPVC לא תומך בכתיבה","volumeMounts.readOnly: true מוגדר ב-Pod spec – מסיר את זה","image שגוי","חסר Secret"],answer:1,explanation:"אם volumeMounts מוגדר עם readOnly: true, ה-container לא יכול לכתוב לvolume גם אם ה-PVC מרשה זאת. יש להסיר readOnly: true מה-volumeMounts."},

    // ── Troubleshooting ──
    {q:"Node עבר לסטטוס NotReady פתאום. מה הצעד הראשון לאבחון?",options:["מחיקת כל הPods שעל ה-Node","kubectl describe node ו-ssh ל-Node לבדוק kubelet logs","kubectl delete node","rollback של אשכול"],answer:1,explanation:"kubectl describe node יציג conditions ולחלץ מידע על הסיבה (DiskPressure, MemoryPressure, NetworkUnavailable). לאחר מכן SSH ל-Node ובדיקת: systemctl status kubelet."},
    {q:"Pod תקוע בסטטוס Terminating כבר 30 דקות. kubectl delete לא עוזר. מה עושים?",options:["chmod על ה-Pod","kubectl delete pod <name> --force --grace-period=0","kubectl restart pod","חיכוי של שעה"],answer:1,explanation:"Pod שתקוע ב-Terminating בד\"כ חכה ל-finalizer שלא הסתיים. --force --grace-period=0 מאלץ מחיקה מיידית. יש להשתמש בזהירות בproduction."},
    {q:"kubectl exec לא עובד על Pod. מקבל 'error: unable to upgrade connection: container not found'. מה הסיבה?",options:["RBAC חסר","ה-container כבר נסגר – Pod אולי ב-CrashLoop","image שגוי","Node תקוע"],answer:1,explanation:"kubectl exec פותח connection ל-container רץ. אם ה-container נסגר (CrashLoop), אין container שניתן ל-exec אליו. יש לבדוק logs ולתקן את הגורם לקריסה."},
    {q:"Cluster autoscaler לא מוסיף Nodes למרות Pods ב-Pending. מה בודקים?",options:["kubectl get pods","לוגים של cluster-autoscaler Pod – ייתכן שיש taint/toleration mismatch, quota, או שאין instance type זמין","kubectl describe node","DNS"],answer:1,explanation:"הAutoscaler מוסיף Nodes רק אם הוא מזהה שPods יכולים לרוץ על Node חדש. אם יש taint שה-Pod לא מסיים, quota שהתמלאה, או בעיה בcloud provider, הוא לא יוסיף."},
    {q:"Node מציג DiskPressure. Pods מתחילים להיות evicted. מה הפתרון המהיר?",options:["יצירת PVC","ניקוי images, logs וקבצים זמניים בNode – docker system prune", "הגדלת memory limits","שינוי namespace"],answer:1,explanation:"DiskPressure מתרחש כשדיסק ה-Node מתמלא. הפתרון המהיר: SSH ל-Node, ניקוי images לא בשימוש (docker/crictl image prune) ולוגים ישנים. לטווח ארוך: הגדלת דיסק או שימוש ב-log rotation."},
    {q:"הפקודה kubectl top nodes נכשלת: 'error: Metrics API not available'. מה חסר?",options:["RBAC","metrics-server לא מותקן באשכול","DNS","StorageClass"],answer:1,explanation:"kubectl top דורש את metrics-server שמספק CPU/memory metrics. ללא זה, גם HPA לא יעבוד. מתקינים: kubectl apply -f https://github.com/kubernetes-sigs/metrics-server/releases/latest/download/components.yaml"},
    {q:"kubectl drain node1 נחסם: 'cannot delete Pods not managed by ReplicationController, ReplicaSet, Job, DaemonSet, or StatefulSet'. מה עושים?",options:["kubectl delete node","מוסיפים --force --ignore-daemonsets","kubectl uncordon","יצירת PDB"],answer:1,explanation:"kubectl drain נחסם כש-Pods standalone (ללא controller) קיימים על ה-Node. --force מאפשר למחוק אותם. --ignore-daemonsets מתעלם מ-DaemonSet Pods שלא ניתן להזיז."},
    {q:"Liveness probe מוגדר על path /healthz ומכשילה כל 30 שניות. הContainer מופעל מחדש כל פעם. האפליקציה עובדת. מה בודקים?",options:["resource limits","ה-liveness probe מגיעה לendpoint שגוי (port/path) או שהתגובה לא 200","image שגוי","NetworkPolicy"],answer:1,explanation:"אם האפליקציה עובדת אבל liveness probe מכשילה, כנראה שה-probe מוגדרת עם port או path שגוי, או שה-endpoint מחזיר status code שאינו 200-399. יש לוודא שהpath והport תואמים את ה-health endpoint של האפליקציה."},
    {q:"אחרי kubectl rollout undo, הDeployment חזר לגרסה קודמת אבל האפליקציה עדיין שבורה. מה בודקים?",options:["kubectl delete deployment","ייתכן שundone חזר לrevision שגם הוא שבור – בודקים rollout history ובוחרים revision ספציפי","kubectl get nodes","DNS"],answer:1,explanation:"kubectl rollout undo חוזר ל-revision הקודם, אבל אם גם הוא היה שבור, זה לא יעזור. kubectl rollout history deployment/my-app מציג את כל ה-revisions, ואפשר לחזור ל-revision ספציפי עם --to-revision=N."},
    {q:"kubectl apply -f manifest.yaml עובד בלי שגיאות, אבל המשאב לא נוצר. מה בודקים?",options:["kubectl delete namespace","kubectl get events -n <namespace> ו-kubectl get <resource> -n <namespace> – ייתכן שהוא נוצר ב-namespace שגוי","RBAC","image"],answer:1,explanation:"apply מצליח מבחינת API server, אבל ה-resource נוצר ב-namespace הגדרת ב-YAML (שאולי שגוי) או ב-default. יש לבדוק kubectl get <resource> --all-namespaces."},
    {q:"Pod חדש לא יכול להיות scheduled על אף Node. kubectl describe pod מציג Taints. מה הפתרון?",options:["מחיקת ה-Pod","הוספת toleration ל-Pod spec שתואמת ל-taint של ה-Nodes","הגדלת CPU","שינוי namespace"],answer:1,explanation:"כש-Node מסומן עם taint, רק Pods שיש להם toleration מתאים יוכלו לרוץ עליו. יש להוסיף ב-Pod spec תחת tolerations: ערך שתואם ל-taint (key, operator, effect)."},
    {q:"etcd Pod בkube-system מציג בעיות. כמה etcd members יש לאשכול בריא בproduction?",options:["1","2","3 (או מספר אי-זוגי)","5 בהכרח"],answer:2,explanation:"etcd דורש quorum – רוב החברים חייבים להיות זמינים. 3 members מאפשרים כשל של 1. 5 מאפשרים כשל של 2. תמיד מספר אי-זוגי כדי למנוע split-brain. לproduction נהוג 3 או 5."},
    {q:"Namespace נמחק אבל תקוע בסטטוס Terminating. kubectl get namespace מציג Terminating כבר שעה. מה הסיבה?",options:["אין RBAC","יש finalizers על resources בתוך ה-namespace שמונעים מחיקה","DNS כשל","etcd בעיה"],answer:1,explanation:"Namespace ב-Terminating בד\"כ תקוע בגלל finalizers שלא הוסרו. יש לזהות את ה-resources עם finalizers (בד\"כ CRDs) ולהסיר אותם ידנית. ניתן לערוך ה-namespace ולמחוק finalizers מה-spec."},
    {q:"Pod רץ על Node1. kubectl drain node1 בוצע. אחרי כמה זמן ה-Pod עובר ל-Node אחר?",options:["מיידית – Kubernetes מזיז Pods בזמן drain","drain מסיים את ה-Pod ואחראי ה-controller (Deployment) יצור Pod חדש על Node אחר","Pod לא יכול לעבור Node","שעה אחרי"],answer:1,explanation:"kubectl drain מסיים (terminates) את ה-Pod על ה-Node. ה-Deployment controller, שמבחין שחסר replica, יצור Pod חדש שה-Scheduler ישים על Node אחר (שאינו cordoned)."},
    {q:"RBAC מוגדר עם ClusterRole אבל ב-namespace ספציפי. איזה binding משתמשים?",options:["ClusterRoleBinding בלבד","RoleBinding – מאפשר שימוש בClusterRole אבל רק בnamespace של ה-RoleBinding","Role","ServiceAccount"],answer:1,explanation:"RoleBinding יכול להתייחס לClusterRole, אבל מגביל את ההרשאות ל-namespace של ה-RoleBinding עצמו. ClusterRoleBinding יתן הרשאות על כל האשכול. לscoped access – משתמשים ב-RoleBinding עם ref ל-ClusterRole."},
    {q:"Pod ב-namespace prod מנסה לקבל ConfigMap מnamespace staging. מה קורה?",options:["זה עובד אוטומטית","Pods לא יכולים לגשת ישירות לresources בnamespaces אחרים","צריך ClusterRole","צריך NetworkPolicy"],answer:1,explanation:"Pods ניגשים לConfigMaps, Secrets, וresources אחרים רק בתוך ה-namespace שלהם. כדי לשתף data בין namespaces, יוצרים עותק בכל namespace או משתמשים ב-external config store."},
    {q:"readinessGate מוגדר על Pod. Pod מציג READY 0/1 למרות שreadiness probe מצליחה. מה בודקים?",options:["liveness probe","readinessGate condition לא נענה – חיצוני לK8s (כגון load balancer sync)","image","DNS"],answer:1,explanation:"readinessGates מאפשרים לגורמים חיצוניים לK8s לקבוע readiness. Pod יהיה Ready רק אחרי שה-condition הנוסף (למשל network load balancer sync) מוגדר כTrue בstatus. יש לבדוק את ה-custom conditions."},
    {q:"נתת kubectl apply על PodDisruptionBudget. drain של Node נכשל: 'Cannot evict pod as it would violate the pod's disruption budget'. מה קרה?",options:["Node בעיה","PDB מגדיר minAvailable=2 אך יש רק 2 Pods – drain יוריד את המספר מתחת לminimum","StorageClass בעיה","NetworkPolicy"],answer:1,explanation:"PDB מגדיר כמה Pods חייבים להישאר זמינים. אם drain ינסה למחוק Pod שיוריד את הכמות מתחת ל-minAvailable, הוא יחסום. הפתרון: לוודא שיש replicas מספיקות לפני drain, או להגדיל את הDeployment."},
    {q:"בdebug של אפליקציה, מריצים kubectl exec pod -- env ורואים שמשתנה SECRET_KEY לא קיים. מה בודקים?",options:["RBAC","האם ה-Secret קיים בnamespace, ואם valueFrom.secretKeyRef נכון ב-YAML של ה-Pod","DNS","NetworkPolicy"],answer:1,explanation:"כשenv var מ-Secret חסר, הסיבות האפשריות: ה-Secret לא קיים, secretName שגוי, key שגוי, או namespace שגוי. kubectl get secret <name> -n <namespace> ו-kubectl describe pod לבדיקת status."},
    {q:"Pod A מנסה לגשת לPod B בport 8080. מחזיר connection timeout. NetworkPolicy לא מוגדרת. מה בודקים?",options:["ה-Pod B בport 8080 לא מאזין – תהליך לא עלה","RBAC","StorageClass","Ingress"],answer:0,explanation:"ללא NetworkPolicy, traffic מוגבל רק על ידי הProcess עצמו. אם timeout ולא refused – ייתכן שהPod B לא מאזין על ה-port הנכון. בודקים: kubectl exec podB -- netstat -tlnp."},
    {q:"Deployment עם 3 replicas. כל הPods מציגים ImagePullBackOff. kubectl describe מציג 'Back-off pulling image'. מה הצעד הראשון?",options:["מחיקת ה-Deployment","בדיקת image tag ב-YAML – האם הtag קיים בregistry","kubectl get nodes","etcd בדיקה"],answer:1,explanation:"ImagePullBackOff אומר שלא ניתן למשוך את ה-image. הסיבות הנפוצות: tag לא קיים, שם image שגוי, או חוסר ב-imagePullSecrets לprivate registry. kubectl describe pod יציג את ה-image name המדויק."},
    {q:"Cluster Kubernetes גדול. נרצה לוודא שPods ייפרסו על Nodes בzones שונות לHA. איך עושים זאת?",options:["Node affinity בלבד","topology spread constraints עם topologyKey: topology.kubernetes.io/zone","DaemonSet","StatefulSet"],answer:1,explanation:"topologySpreadConstraints מאפשרים הגדרה שPods יתפזרו באופן שווה על פני zones (או nodes, racks). מגדירים maxSkew ו-topologyKey לzone. זה עדיף על anti-affinity כי הוא גמיש ומדרגי יותר."},
    {q:"Pod ב-CrashLoop. הלוגים מציגים permission denied על path /data. מה הבעיה?",options:["חסר PVC","ה-container רץ כuser שאין לו הרשאות לwrite ל-/data – בודקים securityContext.runAsUser ו-fsGroup","image שגוי","namespace"],answer:1,explanation:"כשprocess בתוך container מנסה לכתוב לpath שלו אין הרשאות, נקבל permission denied. פתרונות: הגדרת fsGroup ב-securityContext, שינוי ownership בDockerfile, או הרצה כuser עם הרשאות מתאימות."},
    {q:"Namespace מוגדר עם ResourceQuota: requests.cpu=2. Pod חדש מבקש cpu: 4. מה קורה?",options:["Pod מקבל 2 cpu","Pod נדחה – עובר את ה-quota","Pod מקבל 4 cpu","Pod נשאר Pending"],answer:1,explanation:"ResourceQuota אוכפת מגבלות על צריכת משאבים בnamespace. Pod שדורש יותר ממה שנשאר ב-quota יידחה בזמן יצירה עם שגיאת 403."},
    {q:"LimitRange מוגדר בnamespace עם default cpu limit=500m. Pod נוצר ללא cpu limit. מה ה-cpu limit של ה-Pod?",options:["אין limit","500m מה-LimitRange","1 core","ללא הגבלה"],answer:1,explanation:"LimitRange מגדיר ערכי ברירת מחדל לresources. Pod שנוצר ללא limits יקבל את ה-defaults מה-LimitRange של ה-namespace אוטומטית."},
    {q:"DaemonSet מוגדר אך לא רץ על Node חדש שנוסף. מה הסיבה הסבירה?",options:["DaemonSet צריך restart","ל-Node יש Taint שה-DaemonSet אין toleration בשבילו","image שגוי","namespace שגוי"],answer:1,explanation:"DaemonSet מריץ Pod על כל Node, אלא אם ל-Node יש Taint שה-DaemonSet לא מקבל. יש להוסיף toleration מתאים ל-DaemonSet spec."},
    {q:"רוצים שPods של service A לא ירוצו על אותו Node כמו Pods של service B. מה מגדירים?",options:["nodeSelector","pod anti-affinity עם topologyKey: kubernetes.io/hostname","NetworkPolicy","ResourceQuota"],answer:1,explanation:"Pod anti-affinity עם topologyKey: kubernetes.io/hostname מבטיחה שPods עם labels מסוימים לא ישכנו על אותו Node. שימושי לHA ולהפרדת workloads."},
    {q:"HPA מוגדר min=2 max=10 targetCPU=50%. יש 2 Pods ב-CPU 80%. כמה Pods אחרי scale-up?",options:["10","4","3","2"],answer:1,explanation:"HPA מחשב: ceil(currentReplicas × actualMetric/targetMetric) = ceil(2 × 80/50) = ceil(3.2) = 4 replicas. Scale-up הדרגתי, לא קפיצה למקסימום."},
    {q:"kubectl rollout pause deployment/my-app – מה זה עושה?",options:["עוצר את כל ה-Pods","עוצר updates זמנית – שינויים נוספים לא יגרמו לrollout עד ל-resume","מוחק את ה-Deployment","מבצע scale=0"],answer:1,explanation:"rollout pause מאפשר לצבור מספר שינויים ב-Deployment spec ולהחיל אותם בבת אחת עם rollout resume. שימושי לcanary testing."},
    {q:"Pod יצא עם exit code 137. מה המשמעות?",options:["הצלחה (0)","ה-container קיבל SIGKILL – בד\"כ OOMKill","ה-container קיבל SIGTERM","שגיאת network"],answer:1,explanation:"Exit code 137 = 128+9 (SIGKILL). הסיבות הנפוצות: OOMKilled (kernel הרג בגלל memory limit) או kubectl delete --force. בודקים kubectl describe pod לאשר."},
    {q:"Multi-container Pod עם sidecar. שני ה-containers צריכים לשתף קבצים. מה הפתרון?",options:["PVC נפרד","emptyDir volume שמחובר לשני ה-containers","ConfigMap","NetworkPolicy"],answer:1,explanation:"emptyDir נוצר עם ה-Pod ונמחק איתו. שני containers יכולים לחבר אותו ב-paths שונים ולשתף קבצים. זהו הפתרון הסטנדרטי לshared filesystem בתוך Pod."},
    {q:"Pod מוגדר עם hostPath volume ל-/var/run/docker.sock. מה הסיכון?",options:["אין סיכון","ה-container מקבל גישה ל-Docker daemon של ה-Node – אפשר לברוח מה-container לחלוטין","רק read-only","ביצועים נמוכים"],answer:1,explanation:"גישה ל-docker.sock מאפשרת לcontainer להפעיל containers אחרים על ה-Node, לקרוא secrets, ולתקוף את ה-host. זהו container escape vector קלאסי. נמנעים ממנו בproduction."},
    {q:"emptyDir עם medium: Memory מוגדר. מה שונה מemptyDir רגיל?",options:["נשמר לאחר restart","נשמר ב-RAM (tmpfs) – מהיר יותר אבל צורך memory","מוגדל אוטומטית","נשמר ב-etcd"],answer:1,explanation:"emptyDir medium: Memory יוצר tmpfs (RAM-based filesystem). מהיר מאוד אבל צורך memory מהPod. שימושי לcaches עתירי I/O. הנתונים נמחקים עם ה-Pod."},
    {q:"PodSecurityAdmission ב-namespace עם enforce=restricted. Pod ניסה לרוץ ב-privileged mode. מה קרה?",options:["Pod רץ ב-privileged","Pod נדחה ב-admission","Pod רץ ב-reduced mode","RBAC מנע"],answer:1,explanation:"Policy restricted אוסרת privileged containers, hostPath volumes, running as root. Pod שמנסה לחרוג נדחה לפני יצירה על ידי ה-admission controller."},
    {q:"Pod מוגדר עם terminationGracePeriodSeconds: 0. מה קורה כשמוחקים אותו?",options:["Pod ממתין 30 שניות","SIGKILL נשלח מיידית – ללא זמן cleanup","Pod ממשיך לרוץ","SIGTERM ואז SIGKILL אחרי שנייה"],answer:1,explanation:"terminationGracePeriodSeconds: 0 אומר שK8s שולח SIGKILL מיידית ללא SIGTERM. הprocess לא מקבל זמן לcleanup. שימושי בtest environments, מסוכן בproduction."},
    {q:"Deployment עם strategy: Recreate. מה קורה בupgrade?",options:["Rolling update – Pod אחד בכל פעם","כל ה-Pods ישנים נמחקים תחילה ואז Pods חדשים נוצרים – יש downtime","אין שינוי","Blue/Green אוטומטי"],answer:1,explanation:"Recreate strategy גורמת לdowntime מכוון. K8s מסיים את כל ה-Pods הישנים ורק אז יוצר חדשים. מתאים כשאי אפשר להריץ שתי גרסאות במקביל (single-writer DB)."},
    {q:"kubectl apply -f secret.yaml. הSecret נוצר. אחר כך kubectl apply מחדש עם ערכים שונים. מה קורה?",options:["שגיאה – Secret קיים","Secret מתעדכן עם הערכים החדשים","Secret כפול נוצר","שום דבר"],answer:1,explanation:"kubectl apply הוא declarative – אם resource קיים, הוא מתעדכן לפי ה-YAML החדש. בניגוד ל-create שנכשל אם קיים. עדכון Secret עם apply חל על Pods חדשים; Pods קיימים לא מושפעים."},
    {q:"Kubernetes Ingress Controller לא מותקן. Ingress object נוצר. מה קורה?",options:["Ingress עובד עם kube-proxy","Object נוצר ב-etcd אבל לא מתפקד – אין traffic routing","DNS נכשל","Pods נמחקים"],answer:1,explanation:"Ingress object הוא רק ה-API definition. בלי Ingress Controller (nginx, traefik, ALB) שיממש אותו, ה-Ingress לא עושה כלום. Controller צריך להיות מותקן קודם."},
    {q:"Pod צריך לדעת את שמו ואת ה-namespace שלו בזמן ריצה. מה משתמשים?",options:["ConfigMap ידני","Downward API – מזריק metadata של ה-Pod כenv vars","Secret","kubectl env inject"],answer:1,explanation:"Downward API מאפשר לPod לקרוא metadata עצמי (name, namespace, labels, annotations, resources) כenv vars או volume files – ללא ConfigMap חיצוני."},
    {q:"Service Account Token מוזרק ל-Pod. מה ה-path בתוך ה-container?",options:["/etc/secrets","/var/run/secrets/kubernetes.io/serviceaccount","/sa/token","/k8s/token"],answer:1,explanation:"K8s מחבר ServiceAccount token ל-/var/run/secrets/kubernetes.io/serviceaccount/token. גם ca.crt ו-namespace שם. האפליקציה קוראת token לשם אימות מול API server."},
    {q:"kubectl get pods מחזיר 'The connection to the server was refused'. מה הבעיה?",options:["Pods לא קיימים","API server לא פועל או kubeconfig מצביע ל-endpoint שגוי","namespace שגוי","RBAC"],answer:1,explanation:"connection refused ל-API server אומר שהתהליך לא מאזין. סיבות: API server crashed, kubeconfig שגוי, VPN/network בעיה. בודקים: kubectl config view, ping ל-API server IP."},
    {q:"Helm install נכשל: 'release already exists'. מה עושים?",options:["kubectl delete release","helm upgrade --install <release> <chart> – מטפל בשני המקרים","kubectl delete namespace","helm delete chart"],answer:1,explanation:"helm install נכשל אם release קיים. helm upgrade --install ימשיך לעבוד בין אם release קיים (upgrade) ובין אם לא (install). פתרון אחיד לשני המקרים."},
    {q:"ConfigMap מוגדר כenv vars. ConfigMap נמחק. ה-Pod הרץ מושפע?",options:["Pod קורס מיידית","Pod ממשיך לרוץ – env vars הוזרקו בזמן יצירה","ConfigMap מוחזר אוטומטית","Pod מופעל מחדש"],answer:1,explanation:"Env vars מConfigMap מוזרקים לPod בזמן יצירה ונשמרים בmemory של ה-process. מחיקת ConfigMap לא משפיעה על Pod רץ. Pod חדש שינסה לעלות יכשל."},
    {q:"Pod מוגדר עם activeDeadlineSeconds: 300 בJob. מה קורה אחרי 5 דקות?",options:["Pod מושהה","Pod מסומן כFailed ומסיים","Pod מופעל מחדש","שום דבר"],answer:1,explanation:"activeDeadlineSeconds מגדיר זמן מקסימלי לJob/Pod. אחרי שעבר, K8s מסיים ומסמן כFailed. שימושי למניעת Jobs שרצים לנצח."},
    {q:"Rolling update יצר שתי גרסאות שרצות במקביל. מה חשוב לוודא?",options:["version lock","backward compatibility – DB schema וAPI responses חייבים לתמוך בשתי גרסאות","rollback מיידי","כלום"],answer:1,explanation:"בזמן rolling update שתי גרסאות רצות יחד. DB migrations לא יכולות להיות destructive. API responses חייבות להיות תואמות לשתי גרסאות. זהו עיקרון backward compatibility."},
    {q:"Service ExternalName מוגדר. מה הוא עושה?",options:["פותח port חיצוני","יוצר DNS CNAME alias לexternal hostname – ללא proxying","מאפשר גישה מחוץ לcluster","מגדיר firewall rule"],answer:1,explanation:"ExternalName service יוצר CNAME DNS שמפנה לexternal hostname (כמו my-db.external.com). Pods באשכול גישים לשירות חיצוני כאילו הוא internal service."},
    {q:"initContainers: initContainer-2 ממתין ל-initContainer-1. מה ה-behavior?",options:["שניהם מתחילים במקביל","K8s ממתין ש-initContainer-1 יסיים (exit 0) לפני initContainer-2","Container הראשי מתחיל מיד","Pod נמחק"],answer:1,explanation:"init containers רצים sequentially – אחד בכל פעם. K8s מחכה שכל init container יסיים לפני הבא. רק אחרי שכולם הסתיימו, main containers עולים."},
    {q:"NetworkPolicy: podSelector: {} (ריק). מה זה מתאר?",options:["שום Pod","כל ה-Pods בnamespace","כל ה-Pods בכל namespaces","שגיאה בsyntax"],answer:1,explanation:"empty podSelector ב-NetworkPolicy policy spec בוחר כל ה-Pods בnamespace. שונה מnamespaceSelector: {} שבוחר כל הnamespaces. חשוב להבדיל."},
    {q:"Kubernetes Secret גדול מ-1MiB. מה קורה?",options:["נוצר עם אזהרה","נדחה – K8s מגביל objects ל-1MiB","נוצר ב-etcd partition נפרד","Secret מחולק אוטומטית"],answer:1,explanation:"etcd ו-K8s enforces גבול של 1MiB per object (Secret/ConfigMap). לנתונים גדולים, משתמשים בexternal secret store (HashiCorp Vault, AWS Secrets Manager)."},
    {q:"Pod צריך גישה ל-AWS S3 ללא credentials ב-Kubernetes. מה הגישה המומלצת?",options:["Secret עם Access Key","IRSA (IAM Roles for Service Accounts) – K8s SA מחובר ל-AWS IAM Role","ConfigMap עם ARN","hostPath"],answer:1,explanation:"IRSA מאפשר לPod לקבל AWS credentials זמניות דרך projected ServiceAccount token. ללא Secret, ללא rotation ידני. בGKE: Workload Identity. ב-Azure: Workload Identity Federation."},
    {q:"Pod ב-namespace prod מנסה לגשת לService ב-namespace staging. מה ה-DNS הנכון?",options:["my-svc","my-svc.staging","my-svc.staging.svc.cluster.local","staging/my-svc"],answer:2,explanation:"Full DNS name בK8s: <service>.<namespace>.svc.cluster.local. לגישה לservice בnamespace אחר חייבים FQDN או לפחות <service>.<namespace>."},
    {q:"kubectl cordon node1 – מה ההבדל מdrain?",options:["זהה לחלוטין","cordon מסמן Node כunschedulable אבל לא מסיר Pods קיימים; drain גם מסיר Pods","cordon מוחק Pods","drain לא ניתן לביטול"],answer:1,explanation:"cordon: Node לא יקבל Pods חדשים (unschedulable), Pods קיימים ממשיכים לרוץ. drain: cordon + evicts כל Pods שאינם DaemonSets. cordon בלבד משמש לmaintenance הדרגתי."},
    {q:"VPA (Vertical Pod Autoscaler) במצב Auto. מה הוא עושה?",options:["מוסיף Nodes","מכוון resources requests/limits ומפעיל Pods מחדש לפי הצורך","מגדיל replicas","לא עושה כלום"],answer:1,explanation:"VPA Auto mode: מחשב resource recommendations ומיישם אותן על ידי eviction + recreate של Pods. זה גורם לdowntime קצר. בשל כך, VPA ו-HPA לא מומלצים יחד על אותו Deployment."},
    {q:"CronJob יצר יותר ממדיניות ה-concurrencyPolicy. Pod ישן עדיין רץ. מה קורה?",options:["Job חדש נוצר תמיד","בהתאם ל-concurrencyPolicy: Forbid – Job חדש לא ייצר; Replace – Job ישן נמחק","שני Jobs רצים במקביל תמיד","CronJob מושהה"],answer:1,explanation:"concurrencyPolicy: Allow (ברירת מחדל) – Jobs מקבילים. Forbid – Job חדש לא ייצר אם קודמו עדיין רץ. Replace – Job ישן נמחק ונוצר חדש. חשוב לבחור נכון לפי workload."},
    {q:"Pod צריך לרוץ על Node ספציפי לפי hostname. מה הדרך הפשוטה ביותר?",options:["NetworkPolicy","nodeName: <node-name> ב-Pod spec","nodeSelector","taint"],answer:1,explanation:"nodeName שולח Pod ישירות ל-Node ספציפי, עוקף את ה-Scheduler לחלוטין. פשוט אך לא גמיש. לproduction מועדפים nodeSelector או node affinity שמאפשרים label-based matching."},
    {q:"Kubernetes API server זמין. kubectl get pods אבל לא רואה changes חדשים. מה בודקים?",options:["etcd","kubectl cache – מוסיפים --no-cache","watch לא פועל","RBAC"],answer:1,explanation:"kubectl מחזיק cache מקומי. --no-cache מאלץ קריאה ישירה מ-API server. לעיתים cache ישן גורם להצגת נתונים לא מעודכנים, במיוחד לאחר שינויים רבים."},
  ],

  en: [
    // ── Workloads ──
    {q:"A pod named api-server is in CrashLoopBackOff. What is the first step to diagnose?",options:["kubectl delete pod api-server","kubectl logs api-server --previous","kubectl edit pod api-server","kubectl drain node"],answer:1,explanation:"--previous shows logs from the last crashed run. This is always the first step for CrashLoopBackOff — the logs will reveal the startup error."},
    {q:"A pod stays Pending. kubectl describe shows '0/3 nodes available: 3 Insufficient memory'. What is the correct solution?",options:["Restart the pod","Change namespace","Lower the pod's memory requests or add a Node to the cluster","Delete other pods"],answer:2,explanation:"The Scheduler can't find a Node with enough free memory to cover the requests. Lower the pod's memory requirements or add a Node with available memory."},
    {q:"A rolling update is stuck — a new pod is created but never reaches Ready. What is the most common cause?",options:["Image does not exist in repo","The readiness probe is failing on the new pod","No DNS","Missing RBAC"],answer:1,explanation:"When a rollout stalls, the most common reason is a failing readiness probe — Kubernetes waits for the pod to become Ready before updating more pods."},
    {q:"A pod crashed with OOMKilled. What does this mean and what is the next step?",options:["Network issue — check NetworkPolicy","The kernel killed the container because it exceeded its memory limit — increase limits.memory","Corrupt image — repull","CPU throttling — increase CPU"],answer:1,explanation:"OOMKilled = Out Of Memory Killed. The kernel terminated the container because it exceeded the memory limit. Increase limits.memory or investigate a memory leak in the application."},
    {q:"An HPA is configured for a Deployment but doesn't scale despite high CPU. What is the most likely cause?",options:["No Ingress","metrics-server is not installed or not running","maxReplicas is too low","Wrong namespace"],answer:1,explanation:"HPA depends on metrics-server to read CPU/memory metrics. Without metrics-server, HPA can't get the data it needs to make scaling decisions."},
    {q:"An init container fails every attempt with exit code 1 and logs show 'connection refused'. What do you check?",options:["resource limits of the init container","Whether the service the init container is waiting for is actually up and running","Wrong image tag","Wrong namespace"],answer:1,explanation:"Init containers are often used to wait for a dependency. 'connection refused' means the target isn't available. Verify the dependency service is running before the pod starts."},
    {q:"A Deployment tries to run 5 replicas but only 3 start. kubectl describe shows 'pod didn't trigger scale-up'. What do you check?",options:["Cluster autoscaler not configured or nodes can't scale out","Wrong image","Missing secrets","Namespace quota"],answer:0,explanation:"When pods can't be scheduled, the Cluster Autoscaler should add nodes. If it doesn't — check that autoscaling is configured, no quota is full, and cloud instances are available."},
    {q:"A Job runs but never completes. kubectl get job shows COMPLETIONS 0/1 after an hour. What do you investigate?",options:["Delete the job and recreate it","kubectl logs of the Job's pod — the process is likely stuck","kubectl describe node","Change restartPolicy"],answer:1,explanation:"A job that never finishes usually has a stuck process. Check the pod logs to see if it's a deadlock, waiting for input, or an infinite loop."},
    {q:"A pod shows READY 0/1 but STATUS Running. The application inside is working. What is wrong?",options:["Liveness probe failing","Readiness probe failing — the pod won't receive traffic","Wrong image","Low resource limits"],answer:1,explanation:"0/1 Ready means the readiness probe is failing. The pod runs but won't receive traffic from the Service. Check the readiness probe path and port configuration."},
    {q:"A StatefulSet database-0 crashed and won't restart. kubectl describe shows 'volume is already exclusively attached'. What happened?",options:["Missing image","PVC with ReadWriteOnce is attached to another node — node drain was not completed cleanly","Wrong namespace","Missing RBAC"],answer:1,explanation:"ReadWriteOnce allows attachment to only one node at a time. If the previous node didn't fully release the volume (e.g. after a crash), the new pod can't attach it. Wait for the node to detach or force a detach."},

    // ── Networking ──
    {q:"kubectl get endpoints my-svc shows '<none>'. The Service exists and pods are running. What is the issue?",options:["Missing Ingress","The Service selector doesn't match the pod labels","Missing NodePort","Missing NetworkPolicy"],answer:1,explanation:"Empty endpoints almost always mean a selector mismatch between the Service and its pods. Check with kubectl get pods --show-labels."},
    {q:"A pod can't reach another service inside the cluster. curl http://my-svc.default.svc.cluster.local returns 'Could not resolve host'. What do you check?",options:["NetworkPolicy","CoreDNS pods in kube-system — are they running and healthy?","Ingress","Service type"],answer:1,explanation:"A DNS resolution failure inside the cluster points to CoreDNS. Check: kubectl get pods -n kube-system | grep coredns and verify they are Running and Ready."},
    {q:"An Ingress is configured and DNS resolves correctly, but all requests return 404. What do you check?",options:["TLS certificate","The Ingress path rule doesn't match the path the application listens on","Ingress namespace","Pod image"],answer:1,explanation:"A 404 from Ingress usually means a path mismatch. If the app listens on / but the Ingress defines path: /api, requests won't match. Check path and pathType."},
    {q:"A NetworkPolicy was applied to a namespace. Now Pod A can't talk to Pod B in the same namespace. What happened?",options:["NetworkPolicy in K8s is default-deny — no allow rule was defined between the pods","Pods are in different namespaces","Service missing","DNS failure"],answer:0,explanation:"NetworkPolicy in Kubernetes is an additive allow-list. When a policy is applied, all traffic not explicitly allowed is blocked. Add an ingress rule that permits communication within the namespace."},
    {q:"A LoadBalancer Service stays in Pending (EXTERNAL-IP <pending>) on a local single-node cluster. Why?",options:["Missing Ingress","LoadBalancer requires a cloud provider integration — not available in local clusters without tools like MetalLB","Missing DNS","Missing TLS"],answer:1,explanation:"LoadBalancer type relies on a cloud provider (AWS, GCP, Azure) to allocate an external IP. On local clusters (minikube, kind) this isn't available without MetalLB or similar. Use NodePort for local testing."},
    {q:"Pod A can't reach the internet. curl google.com fails, but another pod in the same namespace succeeds. What do you check?",options:["kubectl logs","NetworkPolicy egress rule on the specific pod that blocks outbound traffic","Wrong image","DNS"],answer:1,explanation:"If one pod can't reach the outside but others can, a NetworkPolicy with egress restrictions on that pod's labels is the prime suspect. Check policies applied by label."},
    {q:"A ClusterIP Service is reachable from inside pods, but the NodePort on port 30080 isn't reachable from outside the cluster. What is the likely cause?",options:["Firewall / security group is blocking port 30080","Missing Ingress","Wrong DNS","RBAC"],answer:0,explanation:"NodePort opens a port on all nodes, but an external firewall (security groups, iptables) may block it. Ensure port 30080 is open in the security group and that no iptables rule is blocking it."},

    // ── Config & Security ──
    {q:"A pod fails to access a Secret you created. kubectl describe pod shows 'secret not found'. What do you check?",options:["RBAC","Whether the Secret is in the same namespace as the pod","Secret encryption","Image pull"],answer:1,explanation:"Secrets and pods must be in the same namespace. A Secret in namespace A is not accessible to a pod in namespace B. Verify the Secret was created in the correct namespace."},
    {q:"A ServiceAccount tries to run kubectl get pods and gets 'Forbidden'. A Role exists. What is missing?",options:["Increase resource limits","A RoleBinding that connects the Role to the ServiceAccount","ClusterRole","Secret"],answer:1,explanation:"A Role alone is not enough. A RoleBinding is required to connect the Role (permissions) to the Subject (ServiceAccount). Without a RoleBinding the Role has no effect."},
    {q:"A ConfigMap was updated with new values, but the app in the pod still sees old values. Why?",options:["ConfigMap is invalid","Most apps read ConfigMaps once at startup — the pod needs a restart","RBAC blocked the ConfigMap","Wrong namespace"],answer:1,explanation:"When a ConfigMap is injected as env vars, changes only take effect after a pod restart. As a volume, updates propagate within a few minutes — but the app must re-read the file."},
    {q:"A pod tries to pull from a private Docker registry and gets ImagePullBackOff. What is missing?",options:["Resource limits","imagePullSecrets is not set on the pod spec — the Secret with registry credentials is missing","NetworkPolicy","Node taints"],answer:1,explanation:"To pull from a private registry, the pod needs imagePullSecrets referencing a Secret of type kubernetes.io/dockerconfigjson with registry credentials."},
    {q:"A pod tries to run as root (uid 0) but is rejected. What is the likely reason?",options:["Missing NetworkPolicy","PodSecurityAdmission or PodSecurityPolicy has runAsNonRoot: true configured","Missing PVC","Missing Service"],answer:1,explanation:"Pod Security Admission can block containers from running as root. If the namespace has a restricted or baseline policy, pods requesting root will be rejected. Change securityContext.runAsUser."},
    {q:"A Secret is mounted as an env var: value = 'dXNlcjpwYXNz'. The app receives this string instead of 'user:pass'. What is wrong?",options:["Wrong secret type","Kubernetes decodes Secrets from base64 automatically — if the Secret was created with an already base64-encoded value, the pod receives double-encoded data","RBAC","Wrong namespace"],answer:1,explanation:"Kubernetes automatically decodes Secret values from base64 when injecting into pods. If the Secret was created with an already-encoded value, the pod receives base64 instead of the plaintext. Create the Secret with the raw value."},

    // ── Storage ──
    {q:"A PVC is Pending. kubectl describe pvc shows 'storageclass.storage.k8s.io not found'. What is the issue?",options:["Missing namespace","The StorageClass specified in the PVC does not exist — check with kubectl get storageclass","PV is full","Missing secret"],answer:1,explanation:"The PVC references a StorageClass that doesn't exist. Verify that the storageClassName in the PVC matches one of the existing StorageClasses (kubectl get storageclass)."},
    {q:"Two pods try to mount the same PVC. The second pod stays Pending with 'Multi-Attach error'. Why?",options:["Missing NetworkPolicy","PVC with accessMode ReadWriteOnce (RWO) can only be attached to one node at a time","Missing secret","Resource limits"],answer:1,explanation:"ReadWriteOnce means the volume can only be mounted to one node at a time. If two pods on different nodes try to attach it, the second is blocked. Fix: change to ReadWriteMany if the storage backend supports it."},
    {q:"A helm upgrade fails with 'cannot patch because a resource with that name already exists (not managed by Helm)'. What happened?",options:["Wrong values.yaml","A resource was manually created outside Helm so Helm doesn't manage it — use helm upgrade --force or delete it manually","Wrong namespace","Wrong image"],answer:1,explanation:"Helm tracks resources it created. If a resource was manually created with the same name, Helm can't manage it. You can annotate the resource as managed by Helm or delete it and let Helm recreate it."},
    {q:"A PV was deleted while a PVC still existed. The PVC is now in 'Lost' status. What do you do?",options:["Delete the PVC and wait","Create a new PV with a claimRef pointing to the existing PVC","kubectl restart pvc","Delete namespace"],answer:1,explanation:"When a PV is deleted the PVC enters Lost status. Create a new PV with spec.claimRef referencing the namespace/name of the existing PVC to restore the binding."},
    {q:"A pod tries to write to a volume but gets 'Read-only file system'. A PVC is defined in the YAML. What do you check?",options:["ReadWriteOnce accessMode doesn't support writes","volumeMounts.readOnly: true is set on the pod spec — remove it","Wrong image","Missing Secret"],answer:1,explanation:"If volumeMounts has readOnly: true, the container cannot write to the volume even if the PVC allows it. Remove readOnly: true from volumeMounts."},

    // ── Troubleshooting ──
    {q:"A node suddenly changes to NotReady. What is the first diagnostic step?",options:["Delete all pods on the node","kubectl describe node and SSH to the node to check kubelet logs","kubectl delete node","Roll back the cluster"],answer:1,explanation:"kubectl describe node shows conditions (DiskPressure, MemoryPressure, NetworkUnavailable). Then SSH to the node and run: systemctl status kubelet to get details on why kubelet stopped reporting."},
    {q:"A pod has been stuck in Terminating for 30 minutes. kubectl delete doesn't help. What do you do?",options:["chmod on the pod","kubectl delete pod <name> --force --grace-period=0","kubectl restart pod","Wait an hour"],answer:1,explanation:"A stuck Terminating pod usually has a finalizer that hasn't completed. --force --grace-period=0 forces immediate deletion. Use with caution in production."},
    {q:"kubectl exec fails: 'error: unable to upgrade connection: container not found'. What is the reason?",options:["Missing RBAC","The container has already exited — the pod is likely in CrashLoop","Wrong image","Node issue"],answer:1,explanation:"kubectl exec opens a connection to a running container. If the container has exited (CrashLoop), there is no container to exec into. Check logs and fix the crash cause."},
    {q:"The cluster autoscaler is not adding nodes despite pods being Pending. What do you check?",options:["kubectl get pods","Logs of the cluster-autoscaler pod — possible taint/toleration mismatch, quota hit, or no available instance type","kubectl describe node","DNS"],answer:1,explanation:"The autoscaler adds nodes only if it determines new pods could run on the new node. If there's an unmatched taint, a full quota, or a cloud provider issue, it won't add nodes."},
    {q:"A node is showing DiskPressure. Pods start getting evicted. What is the quick fix?",options:["Create a PVC","Clean up images, logs, and temp files on the node — docker system prune","Increase memory limits","Change namespace"],answer:1,explanation:"DiskPressure occurs when the node's disk fills up. Quick fix: SSH to the node, prune unused images (docker/crictl image prune) and old logs. Long-term: expand disk or implement log rotation."},
    {q:"kubectl top nodes fails: 'error: Metrics API not available'. What is missing?",options:["RBAC","metrics-server is not installed in the cluster","DNS","StorageClass"],answer:1,explanation:"kubectl top requires metrics-server which provides CPU/memory metrics. Without it, HPA won't work either. Install: kubectl apply -f https://github.com/kubernetes-sigs/metrics-server/releases/latest/download/components.yaml"},
    {q:"kubectl drain node1 is blocked: 'cannot delete Pods not managed by ReplicationController, ReplicaSet, Job, DaemonSet, or StatefulSet'. What do you do?",options:["kubectl delete node","Add --force --ignore-daemonsets","kubectl uncordon","Create a PDB"],answer:1,explanation:"kubectl drain is blocked by standalone pods (without a controller). --force allows deleting them. --ignore-daemonsets skips DaemonSet pods that can't be moved."},
    {q:"A liveness probe on path /healthz is failing every 30 seconds, causing the container to restart. The app is actually working. What do you check?",options:["Resource limits","The liveness probe is hitting the wrong port or path, or the response is not a 2xx/3xx status","Wrong image","NetworkPolicy"],answer:1,explanation:"If the app works but the liveness probe fails, the probe is likely misconfigured — wrong port, wrong path, or the health endpoint returns a non-success status. Verify the path and port match the app's health endpoint."},
    {q:"After kubectl rollout undo, the Deployment reverted but the app is still broken. What do you check?",options:["kubectl delete deployment","The undo may have reverted to a revision that was also broken — check rollout history and select a specific revision","kubectl get nodes","DNS"],answer:1,explanation:"kubectl rollout undo reverts to the previous revision, but if that was also broken it won't help. Use kubectl rollout history deployment/my-app to see all revisions, then rollout undo --to-revision=N."},
    {q:"kubectl apply -f manifest.yaml succeeds with no error, but the resource is not created where expected. What do you check?",options:["kubectl delete namespace","kubectl get events and check the namespace — the resource may have been created in the wrong namespace","RBAC","Image"],answer:1,explanation:"apply succeeds at the API level but the resource is created in the namespace defined in the YAML (which may be wrong) or in default. Check: kubectl get <resource> --all-namespaces."},
    {q:"A new pod can't be scheduled on any node. kubectl describe pod shows Taints. What is the fix?",options:["Delete the pod","Add a toleration to the pod spec that matches the node taint","Increase CPU","Change namespace"],answer:1,explanation:"When a node has a taint, only pods with a matching toleration can run on it. Add a tolerations entry to the pod spec that matches the taint (key, operator, effect)."},
    {q:"An etcd pod in kube-system is showing issues. How many etcd members should a healthy production cluster have?",options:["1","2","3 (or any odd number)","Exactly 5"],answer:2,explanation:"etcd requires quorum — a majority of members must be available. 3 members tolerate 1 failure; 5 tolerate 2. Always use an odd number to prevent split-brain. Production typically uses 3 or 5."},
    {q:"A namespace is stuck in Terminating for over an hour. What is the most likely cause?",options:["No RBAC","Finalizers on resources inside the namespace are preventing deletion","DNS failure","etcd issue"],answer:1,explanation:"A namespace stuck in Terminating is almost always blocked by finalizers that haven't been cleared. Identify resources with finalizers (often CRDs) and remove them manually or patch the namespace to remove the finalizers."},
    {q:"A pod is running on node1. kubectl drain node1 is executed. What happens next?",options:["The pod is immediately live-migrated by Kubernetes","drain terminates the pod; the owning controller (Deployment) creates a new pod that the Scheduler places on another node","The pod cannot move nodes","One hour later"],answer:1,explanation:"kubectl drain terminates pods on the node. The Deployment controller notices the missing replica and creates a new pod, which the Scheduler places on a non-cordoned node."},
    {q:"RBAC is configured with a ClusterRole but you only want it to apply to a specific namespace. Which binding do you use?",options:["ClusterRoleBinding only","RoleBinding — allows using a ClusterRole but scopes permissions to the namespace of the RoleBinding","Role","ServiceAccount"],answer:1,explanation:"A RoleBinding can reference a ClusterRole, but it restricts the permissions to the namespace where the RoleBinding lives. ClusterRoleBinding grants cluster-wide access. For scoped access use a RoleBinding pointing to a ClusterRole."},
    {q:"A pod in namespace prod tries to access a ConfigMap from namespace staging. What happens?",options:["It works automatically","Pods cannot directly access resources in other namespaces","A ClusterRole is needed","A NetworkPolicy is needed"],answer:1,explanation:"Pods access ConfigMaps, Secrets, and other resources only within their own namespace. To share data across namespaces, duplicate the resource or use an external config store."},
    {q:"A readinessGate is defined on a pod. The pod shows READY 0/1 even though the readiness probe passes. What do you check?",options:["Liveness probe","The readinessGate condition is not satisfied — it is set by an external controller (e.g. load balancer sync)","Image","DNS"],answer:1,explanation:"ReadinessGates let external controllers determine pod readiness. The pod is only Ready after the additional condition (e.g. network LB sync) is set to True in pod status. Check the custom conditions."},
    {q:"You apply a PodDisruptionBudget. kubectl drain fails: 'Cannot evict pod as it would violate the pod disruption budget'. What happened?",options:["Node issue","PDB defines minAvailable=2 but only 2 pods exist — drain would reduce below the minimum","StorageClass issue","NetworkPolicy"],answer:1,explanation:"PDB defines how many pods must remain available. If drain would reduce the count below minAvailable, it is blocked. Fix: ensure enough replicas exist before draining, or temporarily scale up the Deployment."},
    {q:"While debugging, you run kubectl exec pod -- env and see SECRET_KEY is missing. What do you check?",options:["RBAC","Whether the Secret exists in the namespace and whether valueFrom.secretKeyRef is correct in the pod YAML","DNS","NetworkPolicy"],answer:1,explanation:"When a Secret-sourced env var is missing, check: the Secret exists, secretName is correct, key is correct, and namespace matches. Use kubectl get secret <name> -n <namespace> and kubectl describe pod."},
    {q:"Pod A tries to reach Pod B on port 8080 and gets a connection timeout (not refused). No NetworkPolicy is configured. What do you check?",options:["Pod B is not listening on port 8080 — the process may not have started","RBAC","StorageClass","Ingress"],answer:0,explanation:"Without NetworkPolicy, traffic is only restricted by the process itself. Timeout (not refused) suggests the port is filtered at the network level, or Pod B isn't listening. Check: kubectl exec podB -- netstat -tlnp."},
    {q:"A Deployment with 3 replicas has all pods in ImagePullBackOff. kubectl describe shows 'Back-off pulling image'. What is the first step?",options:["Delete the Deployment","Check the image tag in the YAML — does the tag exist in the registry?","kubectl get nodes","Check etcd"],answer:1,explanation:"ImagePullBackOff means the image can't be pulled. Common causes: tag doesn't exist, wrong image name, or missing imagePullSecrets for a private registry. kubectl describe pod shows the exact image name being requested."},
    {q:"You want pods to be spread across availability zones for HA. What is the best approach?",options:["Node affinity only","topologySpreadConstraints with topologyKey: topology.kubernetes.io/zone","DaemonSet","StatefulSet"],answer:1,explanation:"topologySpreadConstraints spread pods evenly across zones (or nodes, racks). Configure maxSkew and topologyKey for zone. This is preferred over pod anti-affinity as it is more flexible and scalable."},
    {q:"A pod is in CrashLoop. Logs show 'permission denied' on path /data. What is the issue?",options:["Missing PVC","The container runs as a user that lacks write permission to /data — check securityContext.runAsUser and fsGroup","Wrong image","Namespace"],answer:1,explanation:"When a process inside a container can't write to a path, check securityContext. Solutions: set fsGroup so the group owns the mounted volume, fix ownership in the Dockerfile, or run as a user with appropriate permissions."},
    {q:"A namespace has a ResourceQuota of requests.cpu=2. A new pod requests cpu: 4. What happens?",options:["Pod gets 2 cpu","Pod is rejected — it exceeds the quota","Pod gets 4 cpu","Pod stays Pending"],answer:1,explanation:"ResourceQuota enforces resource consumption limits per namespace. A pod requesting more than the remaining quota is rejected at creation time with a 403 error."},
    {q:"A LimitRange in a namespace sets a default cpu limit of 500m. A pod is created with no cpu limit. What is the pod's cpu limit?",options:["No limit","500m from the LimitRange","1 core","Unlimited"],answer:1,explanation:"LimitRange provides default values for resources. A pod created without limits automatically receives the LimitRange defaults for that namespace."},
    {q:"A DaemonSet is defined but not running on a newly added node. What is the most likely reason?",options:["DaemonSet needs restart","The node has a taint the DaemonSet has no toleration for","Wrong image","Wrong namespace"],answer:1,explanation:"DaemonSets run a pod on every node unless the node has a taint that the DaemonSet doesn't tolerate. Add the appropriate toleration to the DaemonSet spec."},
    {q:"You want pods of service A to never run on the same node as pods of service B. What do you configure?",options:["nodeSelector","Pod anti-affinity with topologyKey: kubernetes.io/hostname","NetworkPolicy","ResourceQuota"],answer:1,explanation:"Pod anti-affinity with topologyKey: kubernetes.io/hostname ensures pods with certain labels don't share a node. Useful for HA and workload separation."},
    {q:"An HPA is set min=2 max=10 targetCPU=50%. 2 pods are at 80% CPU. How many pods after scale-up?",options:["10","4","3","2"],answer:1,explanation:"HPA formula: ceil(currentReplicas × actual/target) = ceil(2 × 80/50) = ceil(3.2) = 4 replicas. Scale-up is gradual, not a jump to maximum."},
    {q:"kubectl rollout pause deployment/my-app — what does this do?",options:["Stops all pods","Suspends rollout updates — further spec changes won't trigger a rollout until resume","Deletes the Deployment","Scales to 0"],answer:1,explanation:"rollout pause lets you batch multiple Deployment spec changes and apply them all at once with rollout resume. Useful for canary testing and multi-step changes."},
    {q:"A pod exited with code 137. What does this mean?",options:["Success (0)","The container received SIGKILL — typically OOMKill","The container received SIGTERM","Network error"],answer:1,explanation:"Exit code 137 = 128+9 (SIGKILL). Common causes: OOMKilled (kernel killed for exceeding memory limit) or kubectl delete --force. Check kubectl describe pod to confirm."},
    {q:"A multi-container pod needs both containers to share files. What is the standard solution?",options:["A separate PVC","An emptyDir volume mounted by both containers","A ConfigMap","NetworkPolicy"],answer:1,explanation:"emptyDir is created with the pod and deleted with it. Both containers can mount it at different paths to share files. This is the standard solution for intra-pod shared storage."},
    {q:"A pod mounts a hostPath volume at /var/run/docker.sock. What is the security risk?",options:["No risk","The container gains access to the Node's Docker daemon — full container escape is possible","Read-only access only","Performance degradation"],answer:1,explanation:"Mounting docker.sock lets a container spawn containers on the host, read secrets, and escape the container sandbox entirely. This is a classic container escape vector and must be avoided in production."},
    {q:"An emptyDir volume is configured with medium: Memory. How does it differ from a regular emptyDir?",options:["Data persists after restart","Data is stored in RAM (tmpfs) — faster but consumes pod memory","Size scales automatically","Data is stored in etcd"],answer:1,explanation:"emptyDir medium: Memory creates a tmpfs (RAM-based filesystem). Very fast for high-throughput I/O but counts against the pod's memory budget. Data is lost when the pod terminates."},
    {q:"PodSecurityAdmission is set to enforce=restricted on a namespace. A pod tries to run in privileged mode. What happens?",options:["Pod runs privileged","Pod is rejected at admission","Pod runs in reduced mode","RBAC blocks it"],answer:1,explanation:"The restricted policy forbids privileged containers, hostPath volumes, and running as root. The pod is rejected before creation by the admission controller."},
    {q:"A pod has terminationGracePeriodSeconds: 0. What happens when it is deleted?",options:["Pod waits 30 seconds","SIGKILL is sent immediately — no cleanup time","Pod keeps running","SIGTERM then SIGKILL after 1 second"],answer:1,explanation:"terminationGracePeriodSeconds: 0 causes Kubernetes to send SIGKILL immediately, skipping SIGTERM. The process has no time to clean up. Use only in test environments."},
    {q:"A Deployment uses strategy: Recreate. What happens during an upgrade?",options:["Rolling update — one pod at a time","All old pods are terminated first, then new ones are created — causes downtime","No change","Automatic blue/green"],answer:1,explanation:"Recreate strategy causes intentional downtime. Kubernetes terminates all old pods before creating new ones. Suitable when two versions cannot run simultaneously (e.g. single-writer database)."},
    {q:"kubectl apply is run twice on the same Secret YAML with different values. What happens?",options:["Error — Secret already exists","Secret is updated with the new values","A duplicate Secret is created","Nothing"],answer:1,explanation:"kubectl apply is declarative — if the resource exists it is updated to match the new YAML. Unlike create which fails if the resource exists. Existing running pods are not affected."},
    {q:"An Ingress Controller is not installed. An Ingress object is created. What happens?",options:["Ingress works via kube-proxy","The object is stored in etcd but has no effect — no traffic routing occurs","DNS fails","Pods are deleted"],answer:1,explanation:"An Ingress object is only an API definition. Without an Ingress Controller (nginx, traefik, ALB) to implement it, it does nothing. The controller must be installed first."},
    {q:"A pod needs to know its own name and namespace at runtime. What mechanism do you use?",options:["Manual ConfigMap","Downward API — injects pod metadata as env vars or volume files","Secret","kubectl env inject"],answer:1,explanation:"The Downward API lets a pod read its own metadata (name, namespace, labels, annotations, resource limits) as env vars or files — without any external ConfigMap."},
    {q:"Where is the ServiceAccount token mounted inside a container?",options:["/etc/secrets","/var/run/secrets/kubernetes.io/serviceaccount","/sa/token","/k8s/token"],answer:1,explanation:"Kubernetes mounts the ServiceAccount token at /var/run/secrets/kubernetes.io/serviceaccount/token. The ca.crt and namespace are also there. The app reads the token to authenticate to the API server."},
    {q:"kubectl get pods returns 'The connection to the server was refused'. What is the problem?",options:["No pods exist","The API server is down or kubeconfig points to a wrong endpoint","Wrong namespace","RBAC"],answer:1,explanation:"'connection refused' to the API server means the process isn't listening. Causes: API server crashed, wrong kubeconfig endpoint, VPN/network issue. Check: kubectl config view, ping the API server IP."},
    {q:"helm install fails: 'release already exists'. What is the solution?",options:["kubectl delete release","helm upgrade --install <release> <chart> — works whether the release exists or not","kubectl delete namespace","helm delete chart"],answer:1,explanation:"helm install fails if the release already exists. helm upgrade --install handles both cases: upgrade if it exists, install if it doesn't. The go-to solution for CI/CD pipelines."},
    {q:"A ConfigMap is used as env vars. The ConfigMap is deleted. Does the running pod notice?",options:["Pod crashes immediately","Pod keeps running — env vars were injected at creation time","ConfigMap is auto-recreated","Pod restarts"],answer:1,explanation:"Env vars from a ConfigMap are injected at pod creation and stored in the process's memory. Deleting the ConfigMap has no effect on a running pod. A new pod will fail to start."},
    {q:"A Job has activeDeadlineSeconds: 300. What happens after 5 minutes?",options:["Pod is paused","Pod is marked Failed and terminated","Pod restarts","Nothing"],answer:1,explanation:"activeDeadlineSeconds sets a maximum runtime for a Job. After the deadline, Kubernetes terminates the pod and marks it Failed. Useful to prevent Jobs from running indefinitely."},
    {q:"A rolling update runs two versions simultaneously. What must you ensure?",options:["Version lock","Backward compatibility — DB schema and API responses must work for both versions","Immediate rollback","Nothing"],answer:1,explanation:"During a rolling update both versions run together. DB migrations must not be destructive (no dropped columns). API responses must be compatible with both versions. This is the backward compatibility principle."},
    {q:"A Service of type ExternalName is defined. What does it do?",options:["Opens an external port","Creates a DNS CNAME alias to an external hostname — no proxying","Allows external access to the cluster","Defines a firewall rule"],answer:1,explanation:"ExternalName creates a CNAME DNS record pointing to an external hostname (e.g. my-db.external.com). Pods access the external service as if it were an internal service, without needing IP addresses."},
    {q:"init containers are listed in sequence. initContainer-2 is waiting. What is the behavior?",options:["Both start in parallel","Kubernetes waits for initContainer-1 to exit 0 before starting initContainer-2","Main container starts immediately","Pod is deleted"],answer:1,explanation:"Init containers run sequentially — one at a time. Kubernetes waits for each to complete (exit 0) before starting the next. Only after all init containers finish do the main containers start."},
    {q:"A NetworkPolicy has podSelector: {} (empty). What does this select?",options:["No pods","All pods in the namespace","All pods in all namespaces","Syntax error"],answer:1,explanation:"An empty podSelector in a NetworkPolicy selects all pods in the namespace. This differs from namespaceSelector: {} which selects all namespaces. Important distinction for writing policies."},
    {q:"A Kubernetes Secret exceeds 1MiB. What happens?",options:["Created with a warning","Rejected — Kubernetes enforces a 1MiB object size limit","Stored in a separate etcd partition","Automatically split"],answer:1,explanation:"etcd and Kubernetes enforce a ~1MiB limit per object (Secret/ConfigMap). For larger data, use an external secret store (HashiCorp Vault, AWS Secrets Manager) and inject references."},
    {q:"A pod needs access to AWS S3 without storing credentials in Kubernetes. What is the recommended approach?",options:["Secret with Access Key","IRSA (IAM Roles for Service Accounts) — K8s SA mapped to AWS IAM Role","ConfigMap with ARN","hostPath"],answer:1,explanation:"IRSA allows pods to receive temporary AWS credentials via a projected ServiceAccount token. No Secrets, no manual rotation. GKE equivalent: Workload Identity. Azure: Workload Identity Federation."},
    {q:"A pod in namespace prod needs to reach a service in namespace staging. What DNS name is correct?",options:["my-svc","my-svc.staging","my-svc.staging.svc.cluster.local","staging/my-svc"],answer:2,explanation:"The full K8s DNS name is: <service>.<namespace>.svc.cluster.local. To reach a service in another namespace you must use the FQDN or at minimum <service>.<namespace>."},
    {q:"What is the difference between kubectl cordon and kubectl drain?",options:["They are identical","cordon marks a node unschedulable but doesn't remove existing pods; drain also evicts existing pods","cordon deletes pods","drain cannot be undone"],answer:1,explanation:"cordon: node won't accept new pods, existing pods keep running. drain: cordon + evicts all non-DaemonSet pods. Use cordon alone for gradual maintenance without disrupting running workloads."},
    {q:"A VPA is in Auto mode. What does it do?",options:["Adds nodes","Adjusts resource requests/limits and restarts pods as needed","Increases replica count","Does nothing"],answer:1,explanation:"VPA Auto mode calculates resource recommendations and applies them by evicting and recreating pods. This causes brief downtime. VPA and HPA are generally not recommended together on the same Deployment."},
    {q:"A CronJob has concurrencyPolicy: Forbid. The previous job is still running when the next is scheduled. What happens?",options:["A new job is always created","The new job is skipped — Forbid prevents concurrent runs","Both jobs run in parallel","CronJob is suspended"],answer:1,explanation:"concurrencyPolicy: Allow (default) — concurrent jobs OK. Forbid — skip new job if previous still running. Replace — delete old job and create new one. Choose based on workload requirements."},
    {q:"You want a pod to run on a specific node by hostname. What is the simplest approach?",options:["NetworkPolicy","nodeName: <node-name> in pod spec","nodeSelector","Taint"],answer:1,explanation:"nodeName sends the pod directly to a specific node, bypassing the Scheduler entirely. Simple but inflexible. For production, prefer nodeSelector or node affinity which use label-based matching."},
    {q:"A pod needs to access the Kubernetes API from inside the cluster. What is the API server address?",options:["https://kube-apiserver:6443","https://kubernetes.default.svc.cluster.local","http://localhost:8080","https://apiserver:443"],answer:1,explanation:"Inside the cluster, the API server is accessible via the special Service: kubernetes.default.svc.cluster.local:443. This ClusterIP Service is created automatically in the default namespace."},
    {q:"After a kubectl apply, the Deployment doesn't update. The old image is still running. What do you check?",options:["kubectl delete","kubectl rollout history — the image tag may not have changed so K8s sees no diff","kubectl restart","DNS"],answer:1,explanation:"Kubernetes detects changes by hashing the pod template. If the image tag (like 'latest') didn't change, Kubernetes sees no diff and skips the rollout. Use a unique tag or image digest (sha256) per build."},
    {q:"A pod QoS class is BestEffort. What happens during memory pressure?",options:["It is never evicted","BestEffort pods are evicted first during memory pressure","They are prioritised","They run on separate nodes"],answer:1,explanation:"Kubernetes defines 3 QoS classes: Guaranteed (requests=limits), Burstable (requests<limits), BestEffort (no requests/limits). During memory pressure, BestEffort is evicted first, then Burstable, then Guaranteed."},
    {q:"A pod has a CPU limit of 200m but the app needs 500m at peak. What happens?",options:["Pod is deleted","CPU throttling — the container runs slower but is not killed","Pod is restarted","Pod is OOMKilled"],answer:1,explanation:"CPU limit causes throttling, not eviction. The container gets less CPU time and runs slower. Unlike memory, exceeding CPU limit does not kill the pod. This is an important distinction."},
    {q:"A ConfigMap is mounted as a volume. Its value is updated. When does the pod see the new value?",options:["Immediately","Within a few minutes (kubelet sync TTL) — no restart needed","Only after pod restart","Only after redeployment"],answer:1,explanation:"When a ConfigMap is mounted as a volume, kubelet syncs changes within about 1-2 minutes. The files in the volume are updated in place. However, if the app reads the file only at startup it still needs a restart."},
    {q:"kubectl rollout status deployment/my-app is stuck for a long time. What is a common cause to check?",options:["etcd is down","progressDeadlineSeconds exceeded — the new pod never reached Ready","DNS failure","StorageClass"],answer:1,explanation:"progressDeadlineSeconds (default 600s) defines how long Kubernetes waits for a rollout to succeed. If exceeded, the Deployment enters a Failed condition. Check pod events to find why the pod isn't reaching Ready."},
  ],
};
